'use client';

import { useEffect } from 'react';

interface DonationSuccessModalProps {
  isOpen: boolean;
  onClose: () => void;
  donationData: {
    deviceName: string;
    ecoPoints: number;
    co2Saved: number;
    donationType: string;
    destinationPath: string;
  } | null;
}

export default function DonationSuccessModal({ isOpen, onClose, donationData }: DonationSuccessModalProps) {
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      
      // Auto close after 8 seconds
      const timer = setTimeout(() => {
        onClose();
      }, 8000);

      return () => {
        clearTimeout(timer);
        document.body.style.overflow = 'unset';
      };
    } else {
      document.body.style.overflow = 'unset';
    }
  }, [isOpen, onClose]);

  if (!isOpen || !donationData) return null;

  const isDonated = donationData.donationType === 'donated';

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-2xl shadow-2xl max-w-md w-full mx-4 transform transition-all duration-300 scale-100">
        {/* Header */}
        <div className={`p-6 rounded-t-2xl ${isDonated ? 'bg-gradient-to-r from-green-500 to-emerald-500' : 'bg-gradient-to-r from-orange-500 to-amber-500'} text-white text-center`}>
          <div className="w-16 h-16 bg-white bg-opacity-20 rounded-full flex items-center justify-center mx-auto mb-4">
            <i className={`${isDonated ? 'ri-gift-line' : 'ri-recycle-line'} text-3xl`}></i>
          </div>
          <h2 className="text-2xl font-bold mb-2">
            {isDonated ? 'Device Donated!' : 'Device Recycled!'}
          </h2>
          <p className="text-white text-opacity-90">
            Thank you for making a difference!
          </p>
        </div>

        {/* Content */}
        <div className="p-6">
          {/* Device Info */}
          <div className="text-center mb-6">
            <h3 className="text-lg font-semibold text-gray-800 mb-2">
              {donationData.deviceName}
            </h3>
            <p className="text-gray-600">
              {isDonated 
                ? 'Your device will help someone in our community' 
                : 'Your device will be responsibly recycled'
              }
            </p>
          </div>

          {/* Impact Stats */}
          <div className="grid grid-cols-2 gap-4 mb-6">
            <div className="text-center p-4 bg-green-50 rounded-xl">
              <div className="text-2xl font-bold text-green-600 mb-1">
                +{donationData.ecoPoints}
              </div>
              <div className="text-sm text-gray-600">Eco Points</div>
            </div>
            <div className="text-center p-4 bg-blue-50 rounded-xl">
              <div className="text-2xl font-bold text-blue-600 mb-1">
                {donationData.co2Saved}kg
              </div>
              <div className="text-sm text-gray-600">CO₂ Saved</div>
            </div>
          </div>

          {/* Journey Info */}
          <div className={`p-4 rounded-xl mb-6 ${isDonated ? 'bg-green-50 border border-green-200' : 'bg-orange-50 border border-orange-200'}`}>
            <div className="flex items-center gap-3">
              <div className={`w-10 h-10 rounded-full flex items-center justify-center ${isDonated ? 'bg-green-500' : 'bg-orange-500'}`}>
                <i className={`${isDonated ? 'ri-user-heart-line' : 'ri-plant-line'} text-white`}></i>
              </div>
              <div>
                <div className="font-semibold text-gray-800">
                  {isDonated ? 'Going to Community' : 'Going to Recycling'}
                </div>
                <div className="text-sm text-gray-600">
                  {isDonated 
                    ? 'A community member will receive your device'
                    : 'Materials will be recovered and reused'
                  }
                </div>
              </div>
            </div>
          </div>

          {/* Action Buttons */}
          <div className="flex gap-3">
            <button
              onClick={onClose}
              className="flex-1 bg-gray-100 hover:bg-gray-200 text-gray-700 py-3 px-4 rounded-xl font-semibold transition-colors whitespace-nowrap"
            >
              Close
            </button>
            <button
              onClick={() => {
                onClose();
                window.location.href = '/dashboard';
              }}
              className="flex-1 bg-green-500 hover:bg-green-600 text-white py-3 px-4 rounded-xl font-semibold transition-colors whitespace-nowrap"
            >
              View Dashboard
            </button>
          </div>
        </div>

        {/* Close Button */}
        <button
          onClick={onClose}
          className="absolute top-4 right-4 w-8 h-8 bg-white bg-opacity-20 hover:bg-opacity-30 rounded-full flex items-center justify-center text-white transition-colors"
        >
          <i className="ri-close-line"></i>
        </button>

        {/* Progress Bar */}
        <div className="absolute bottom-0 left-0 right-0 h-1 bg-gray-200 rounded-b-2xl overflow-hidden">
          <div 
            className="h-full bg-green-500 transition-all duration-8000 ease-linear"
            style={{
              width: '100%',
              animation: 'progress 8s linear forwards'
            }}
          ></div>
        </div>
      </div>

      <style jsx>{`
        @keyframes progress {
          from { width: 100%; }
          to { width: 0%; }
        }
      `}</style>
    </div>
  );
}